class Solution:
    def concatenatedDivisibility(self, nums, k):
        from itertools import permutations
        best = None
        for perm in permutations(range(len(nums))):
            cat = ''.join(str(nums[i]) for i in perm)
            if int(cat) % k == 0:
                lst = [nums[i] for i in perm]
                if best is None or lst < best:
                    best = lst
        return best if best is not None else []

