class Solution:
    def concatenatedDivisibility(self, nums, k):
        from functools import lru_cache
        n = len(nums)
        pw = [pow(10, len(str(x)), k) for x in nums]
        mod = [x % k for x in nums]
        full = (1 << n) - 1
        @lru_cache(maxsize=None)
        def can_finish(mask, rem):
            if mask == full:
                return rem == 0
            for i in range(n):
                if not (mask >> i) & 1:
                    nr = (rem * pw[i] + mod[i]) % k
                    if can_finish(mask | (1 << i), nr):
                        return True
            return False
        if not can_finish(0, 0):
            return []
        mask = 0
        rem = 0
        res = []
        for _ in range(n):
            cands = sorted((i for i in range(n) if not (mask >> i) & 1), key=lambda i: (nums[i], i))
            for i in cands:
                nr = (rem * pw[i] + mod[i]) % k
                if can_finish(mask | (1 << i), nr):
                    res.append(nums[i])
                    mask |= (1 << i)
                    rem = nr
                    break
        return res

