var concatenatedDivisibility = function(nums, k) {
    const n = nums.length;
    const pw = nums.map(x => {
        let p = 1;
        const d = String(x).length;
        for (let i = 0; i < d; i++) p = (p * 10) % k;
        return p;
    });
    const mod = nums.map(x => x % k);
    const full = (1 << n) - 1;
    const memo = new Map();
    function canFinish(mask, rem) {
        if (mask === full) return rem === 0;
        const key = mask * k + rem;
        if (memo.has(key)) return memo.get(key);
        let res = false;
        for (let i = 0; i < n; i++) {
            if (!((mask >> i) & 1)) {
                const nr = (rem * pw[i] + mod[i]) % k;
                if (canFinish(mask | (1 << i), nr)) { res = true; break; }
            }
        }
        memo.set(key, res);
        return res;
    }
    if (!canFinish(0, 0)) return [];
    let mask = 0, rem = 0;
    const out = [];
    for (let step = 0; step < n; step++) {
        const cands = [];
        for (let i = 0; i < n; i++) if (!((mask >> i) & 1)) cands.push(i);
        cands.sort((a, b) => nums[a] !== nums[b] ? nums[a] - nums[b] : a - b);
        for (const i of cands) {
            const nr = (rem * pw[i] + mod[i]) % k;
            if (canFinish(mask | (1 << i), nr)) {
                out.push(nums[i]); mask |= (1 << i); rem = nr; break;
            }
        }
    }
    return out;
};
